   216	        public async Task<bool> RemoveFileAsync(IBrowserFile file)
   217	        {
   218	            if (file is null)
   219	            {
   220	                Logger.LogWarning("Attempted to remove a null file.");
   221	                return false;
   222	            }
   223	
   224	            var current = _filesState.Value;
   225	
   226	            switch (current)
   227	            {
   228	                case IBrowserFile singleFile when ReferenceEquals(singleFile, file):
   229	                    // Single selection with the same instance: clear selection
   230	                    await _filesState.SetValueAsync(default);
   231	                    return true;
   232	
   233	                case IReadOnlyList<IBrowserFile> fileList:
   234	                    {
   235	                        // Remove this specific instance (reference-based via List.Remove)
   236	                        var updatedList = fileList.ToList();
   237	                        if (!updatedList.Remove(file))
   238	                        {
   239	                            Logger.LogDebug("The specified file instance was not found in the current selection.");
   240	                            return false;
   241	                        }
   242	
   243	                        if (updatedList.Count == 0)
   244	                        {
   245	                            await _filesState.SetValueAsync(default);
   246	                        }
   247	                        else
   248	                        {
   249	                            await _filesState.SetValueAsync((T)(object)updatedList);
   250	                        }
   251	
   252	                        return true;
   253	                    }
   254	
   255	                case null:
   256	                    Logger.LogDebug("No files are currently selected.");
   257	                    return false;
   258	
   259	                default:
   260	                    Logger.LogWarning(
   261	                        "File removal by instance is not supported for the current files type '{Type}'.",
   262	                        current.GetType().FullName);
   263	                    return false;
   264	            }
   265	        }
