/// <summary>
        /// Tests drag and drop with custom content - verifies that dragenter on custom content
        /// triggers the input overlay to become visible, and dragleave on the input resets the state.
        /// Reproduces: https://github.com/MudBlazor/MudBlazor/issues/XXXX
        /// When DragAndDrop=true and CustomContent is used, the InputFile overlay appears on dragenter
        /// and captures subsequent drag events, preventing @ondragleave on custom content from firing.
        /// </summary>
        [Test]
        public async Task FileUpload_DragAndDrop_CustomContent_DragLeave_Test()
        {
            var comp = Context.Render<FileUploadDragLeaveCustomContentTest>();

            // Drag enter on custom content should work
            var customPaper = comp.Find(".mud-paper");
            await customPaper.DragEnterAsync();
            comp.Instance.DragEnterFiredOnCustomContent.Should().BeTrue();

            // After drag enter, the input overlay becomes visible
            var input = comp.Find("input");
            input.HasAttribute("hidden").Should().BeFalse();

            // Now simulate drag leave on the input overlay (which is what happens in reality)
            // The input overlay captures the dragleave because it's positioned on top
            await input.DragLeaveAsync();

            // The dragleave should have ALSO fired on the custom content (or the state should be reset)
            // This is what the bug report is about - dragleave doesn't fire on custom content
            // because the input overlay captures it
            comp.Instance.DragLeaveFiredOnCustomContent.Should().BeTrue();

            // The drag class should be reset
            customPaper.ClassList.Should().NotContain("mud-border-primary");
        }

