/// <summary>
        /// Tests drag and drop with custom content - verifies that @ondragleave set on MudFileUpload
        /// actually fires when a dragleave event occurs on the InputFile.
        /// The issue is that explicit @ondragleave="OnDragResetAsync" on InputFile overrides
        /// the user's @ondragleave handler because @attributes="UserAttributes" comes BEFORE it.
        /// </summary>
        [Test]
        public async Task FileUpload_DragAndDrop_CustomContent_DragLeave_Test()
        {
            var comp = Context.Render<FileUploadDragLeaveCustomContentTest>();

            // Drag enter on custom content should work
            var customPaper = comp.Find(".mud-paper");
            await customPaper.DragEnterAsync();
            comp.Instance.DragEnterFired.Should().BeTrue();

            // After drag enter, the input overlay becomes visible
            var input = comp.Find("input");
            input.HasAttribute("hidden").Should().BeFalse();

            // Simulate drag leave on the input overlay
            // The user's @ondragleave handler should fire
            await input.DragLeaveAsync();

            // VERIFY: User's @ondragleave handler was called
            comp.Instance.DragLeaveFired.Should().BeTrue("because the user's @ondragleave handler should fire");

            // The drag class should be reset
            customPaper.ClassList.Should().NotContain("mud-border-primary");
        }

